def transition(state, action):
    s = dict(state)
    name = action.get("name")
    params = action.get("params") or {}

    factors = s.get("risk_factors", {})

    # An action may retarget the active risk pool before pricing.
    requested = params.get("risk_pool")
    if requested in factors:
        s["risk_pool"] = requested
    pool = s.get("risk_pool")
    factor = factors.get(pool, 1.0)

    def price(load):
        return round(s.get("base_premium", 0.0) * factor * (1.0 + load), 2)

    status = s.get("policy_status", "none")

    if name == "quote":
        s["quoted_premium"] = price(s.get("claims_load", 0.0))
        s["policy_status"] = "quoted"

    elif name == "bind":
        if status == "quoted":
            s["bound_premium"] = s.get("quoted_premium", 0.0)
            s["policy_status"] = "bound"
            s["policies_in_force"] = s.get("policies_in_force", 0) + 1
            s["written_premium"] = round(
                s.get("written_premium", 0.0) + s["bound_premium"], 2)

    elif name == "renew":
        if status == "bound":
            load = round(s.get("claims_load", 0.0) + s.get("renewal_drift", 0.05), 4)
            s["claims_load"] = load
            new_premium = price(load)
            s["bound_premium"] = new_premium
            s["quoted_premium"] = new_premium
            s["renewals"] = s.get("renewals", 0) + 1
            s["written_premium"] = round(
                s.get("written_premium", 0.0) + new_premium, 2)

    elif name == "lapse":
        if status == "bound":
            s["policy_status"] = "lapsed"
            s["policies_in_force"] = max(0, s.get("policies_in_force", 0) - 1)
            s["lapsed_count"] = s.get("lapsed_count", 0) + 1

    return s

