def perceive(data):
    text = data if isinstance(data, str) else str(data)
    out = {}
    for line in text.splitlines():
        if ":" not in line:
            continue
        key, _, val = line.partition(":")
        key = key.strip().lower().replace(" ", "_")
        val = val.strip()
        if key in ("risk_pool", "pool"):
            out["risk_pool"] = val.lower()
        elif key in ("base_premium", "premium", "base"):
            cleaned = val.replace(",", "").replace("$", "")
            try:
                out["base_premium"] = float(cleaned)
            except ValueError:
                pass
    return out
